// Sofia Adaptive Follow-up Engine
const items = [];
const now = new Date();

for (const item of $input.all()) {
  const data = item.json;
  const lastContact = new Date(data.timestamp || now);
  const hoursAgo = (now - lastContact) / (1000 * 60 * 60);
  const customerType = data.tipo_cliente || 'prospect';
  const score = parseInt(data.score_cliente) || 50;
  const lastAction = data.decisao_sofia || 'unknown';

  // ADAPTIVE FOLLOW-UP RULES
  let shouldFollowUp = false;
  let followUpType = 'none';
  let priority = 'low';
  let message = '';

  // EX-ALUNOS WORKFLOW
  if (customerType === 'ex_aluno') {
    if (score >= 70 && hoursAgo >= 24 && !data.seguimento_feito) {
      shouldFollowUp = true;
      followUpType = 'ex_aluno_hot';
      priority = 'high';
      message = `Oi! Pensei em você hoje! 😊\n\nJá decidiu sobre voltar a treinar? Aquela oferta de 20% off + semana grátis ainda vale!\n\nE tem mais: chegaram equipamentos novos que você vai adorar! 🏋️‍♀️\n\nQuer que eu separe um horário para você conhecer as novidades?`;
    } else if (score >= 50 && hoursAgo >= 72) {
      shouldFollowUp = true;
      followUpType = 'ex_aluno_warm';
      priority = 'medium';
      message = `E aí! Como você está? 💪\n\nVi que você demonstrou interesse em voltar... A Full Force está com cara nova!\n\n🎁 Que tal uma visita sem compromisso?\n🏋️‍♀️ Posso mostrar tudo que mudou\n⏰ 15 minutos do seu tempo\n\nQual o melhor dia para você?`;
    }
  }

  // FREE PASS WORKFLOW
  else if (customerType === 'free_pass') {
    if (hoursAgo >= 48 && lastAction !== 'oferecer_planos') {
      shouldFollowUp = true;
      followUpType = 'free_pass_conversion';
      priority = 'high';
      message = `Como estão sendo seus treinos? 🎉\n\nJá são ${Math.floor(hoursAgo/24)} dias do seu Free Pass! O tempo está voando, né?\n\n**OFERTA ESPECIAL PARA VOCÊ:**
💥 Matrícula sem taxa (economia R$ 50)
💥 Primeiro mês R$ 149 (desconto R$ 30)
💥 Garante sua vaga nos horários que você gosta
\nSó até amanhã! Confirmo para você? 🚀`;
    } else if (hoursAgo >= 120) { // 5 dias
      shouldFollowUp = true;
      followUpType = 'free_pass_urgent';
      priority = 'urgent';
      message = `Oi! Seu Free Pass está acabando hoje! 😱\n\nNão queremos que você pare de treinar! Que tal garantir sua continuidade?\n\n🔥 **ÚLTIMA CHANCE:**
✅ Sem taxa de matrícula
✅ Desconto especial primeiro mês
✅ Mesmos horários que você já conhece
\nPosso processar sua matrícula agora mesmo! O que acha? 💪`;
    }
  }

  // AMIGO BÔNUS WORKFLOW
  else if (customerType === 'amigo_bonus') {
    if (hoursAgo >= 168 && !data.conversao_tentada) { // 7 dias
      shouldFollowUp = true;
      followUpType = 'amigo_engagement';
      priority = 'medium';
      message = `E aí! Como está sendo treinar na Full Force? 💪\n\nJá uma semana que você está conosco! Sentindo a diferença?\n\nSeu amigo teve uma ótima ideia te trazendo aqui! 😊\n\nConta pra mim: qual exercício você mais gostou até agora?`;
    } else if (hoursAgo >= 600) { // 25 dias (5 dias antes do fim)
      shouldFollowUp = true;
      followUpType = 'amigo_conversion';
      priority = 'urgent';
      message = `Seu mês de cortesia está chegando ao fim! 😱\n\nMas não queremos que você vá embora! Você já faz parte da família Full Force! 🏋️‍♀️\n\n**OFERTA EXCLUSIVA AMIGO:**
🎁 30% de desconto nos primeiros 3 meses
🎁 Sem taxa de matrícula
🎁 Você pode trazer outro amigo grátis também!\n\nVamos continuar juntos? Só preciso confirmar! 🚀`;
    }
  }

  // PROSPECTS NORMAIS
  else if (customerType === 'prospect') {
    if (score >= 60 && hoursAgo >= 48) {
      shouldFollowUp = true;
      followUpType = 'prospect_nurture';
      priority = 'medium';
      message = `Oi! Tudo bem? 😊\n\nVi que você tem interesse na Full Force Academia!\n\nQue tal conhecer? Nosso Free Pass de 5 dias é perfeito para você experimentar sem pressa!\n\n🎁 Totalmente grátis
🏋️‍♀️ Conhece todos os equipamentos
👥 Sente o clima da nossa comunidade
\nPosso agendar para quando você preferir! Que dia é bom?`;
    }
  }

  if (shouldFollowUp) {
    items.push({
      json: {
        telefone: data.telefone,
        tipo_seguimento: followUpType,
        prioridade: priority,
        mensagem: message,
        score_cliente: score,
        tipo_cliente: customerType,
        horas_desde_ultimo_contato: Math.round(hoursAgo),
        timestamp_seguimento: now.toISOString(),
        contexto_original: data.contexto_detectado,
        acao_anterior: lastAction
      }
    });
  }
}

console.log(`Sofia identificou ${items.length} follow-ups para executar`);
return items;

// Sofia Learning & Optimization Engine
const results = $input.all();
const timestamp = new Date().toISOString();

// Análise de performance
const successful = results.filter(r => r.json.success || !r.json.error).length;
const failed = results.length - successful;
const successRate = ((successful / results.length) * 100).toFixed(1);

// Análise por tipo de follow-up
const byType = {};
results.forEach(r => {
  const type = r.json.tipo_seguimento || 'unknown';
  if (!byType[type]) byType[type] = { sent: 0, success: 0 };
  byType[type].sent++;
  if (r.json.success || !r.json.error) byType[type].success++;
});

// Otimizações sugeridas
const optimizations = [];
if (successRate < 85) {
  optimizations.push('Ajustar horários de envio');
}
if (byType.ex_aluno_hot?.success / byType.ex_aluno_hot?.sent < 0.8) {
  optimizations.push('Melhorar mensagens para ex-alunos quentes');
}
if (byType.free_pass_conversion?.success / byType.free_pass_conversion?.sent < 0.7) {
  optimizations.push('Revisar estratégia de conversão Free Pass');
}

return {
  timestamp: timestamp,
  total_followups: results.length,
  successful_sends: successful,
  failed_sends: failed,
  success_rate: successRate + '%',
  performance_by_type: byType,
  optimizations_suggested: optimizations,
  next_analysis: new Date(Date.now() + 3*60*60*1000).toISOString(), // 3 horas
  academy: 'Full Force Academia',
  sofia_engine_version: '1.0'
};
